package com.github.shepherdviolet.glacimon.java.crypto.experiment;

import java.math.BigInteger;

import static com.github.shepherdviolet.glacimon.java.crypto.experiment.CtfRsaUtils.*;
import static com.github.shepherdviolet.glacimon.java.crypto.experiment.CtfRsaUtils.stringToBigInteger;

/**
 * [CTF用] 用BigInteger实现的RSA加解密工具 示例
 */
public class CtfRsaUtilsDemo {

    public static void main(String[] args) throws Exception {

        // 引入工具类所有方法: import static com.github.shepherdviolet.glacimon.java.crypto.experiment.CtfRsaUtils.*;

        BigInteger c; // 密文
        BigInteger m; // 明文
        BigInteger d;
        BigInteger n;

        // 从文件读取BigInteger (支持二进制文件, 十进制文本, 十六进制文本, BASE64文本)
//        c = readBigIntegerFromFile(new File("D:\\__Download\\虚机中转\\flag.txt"), null);
//        System.out.println(c);

        // 文本转BigInteger (十进制文本, 十六进制文本, BASE64文本)
        c = stringToBigInteger("1234567890");
        System.out.println("c: " + c);
        c = stringToBigInteger("0x6f23ab9f");
        System.out.println("c: " + c);
        c = stringToBigInteger("6f23ab9f");
        System.out.println("c: " + c);
        c = stringToBigInteger("");
        System.out.println("c: " + c);

        // pqe求d, 入参: p q e
        d = pqeToD(stringToBigInteger(""),
                stringToBigInteger(""),
                stringToBigInteger("65537"));
        System.out.println("d: " + d);

        n = pqToN(stringToBigInteger(""),
                stringToBigInteger(""));
        System.out.println("n: " + n);

        // dn解密c, 入参: c d n
        m = decrypt(stringToBigInteger(""),
                stringToBigInteger(""),
                stringToBigInteger(""));
        System.out.println("m: " + bigIntegerToString(m, null));

        // pqe解密c, 入参: c p q e
        m = decryptWithPQE(stringToBigInteger(""),
                stringToBigInteger(""),
                stringToBigInteger(""),
                stringToBigInteger("65537"));
        System.out.println("m: " + bigIntegerToString(m, null));

    }

}
